import{_ as t,o,c as a,a2 as i}from"./chunks/framework.Bk_3gXAz.js";const m=JSON.parse(`{"title":"cm-how-it-work","description":"Complete guide to vibe coding with the CodyMaster skill kit — from idea to deploy. Covers the full workflow, skills used at each phase, and common use cases. Read this first if you are new; reference it whenever you're unsure which skill to invoke.","frontmatter":{"title":"cm-how-it-work","name":"cm-how-it-work","description":"Complete guide to vibe coding with the CodyMaster skill kit — from idea to deploy. Covers the full workflow, skills used at each phase, and common use cases. Read this first if you are new; reference it whenever you're unsure which skill to invoke."},"headers":[],"relativePath":"skills/cm-how-it-work.md","filePath":"skills/cm-how-it-work.md"}`),r={name:"skills/cm-how-it-work.md"};function n(s,e,d,l,c,u){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="codymaster-kit-—-the-ultimate-vibe-coding-guide" tabindex="-1">CodyMaster Kit — The Ultimate Vibe Coding Guide <a class="header-anchor" href="#codymaster-kit-—-the-ultimate-vibe-coding-guide" aria-label="Permalink to &quot;CodyMaster Kit — The Ultimate Vibe Coding Guide&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <strong>CodyMaster (CM)</strong> kit transforms ideas into production code through 13 specialized, optimized skills. This workflow ensures the highest quality, absolute security, and maximum execution speed.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>💡 Idea → 🔍 Analysis → 📐 Design → 🧪 Test-first (TDD) → 💻 Code → ✅ Verify → 🚀 Deploy → 🔄 Iterate</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h2><h3 id="phase-0-identity-safety-🔒" tabindex="-1">Phase 0: Identity &amp; Safety 🔒 <a class="header-anchor" href="#phase-0-identity-safety-🔒" aria-label="Permalink to &quot;Phase 0: Identity &amp; Safety 🔒&quot;">​</a></h3><blockquote><p><strong>Rule #1:</strong> Always verify identity before performing any action that could change the project state.</p></blockquote><ul><li><strong>Skill:</strong> <code>cm-identity-guard</code></li><li><strong>When:</strong> At the start of a work session, before git push, deploy, or database operations.</li><li><strong>Action:</strong> Run <code>node check-identity.js</code> (or similar script) to verify GitHub/Cloudflare/Supabase accounts.</li></ul><hr><h3 id="phase-0-5-strategic-analysis-🔍" tabindex="-1">Phase 0.5: Strategic Analysis 🔍 <a class="header-anchor" href="#phase-0-5-strategic-analysis-🔍" aria-label="Permalink to &quot;Phase 0.5: Strategic Analysis 🔍&quot;">​</a></h3><blockquote><p><strong>For complex initiatives and enhancements on existing products.</strong></p></blockquote><ul><li><strong>Skills:</strong> <code>cm-brainstorm-idea</code> + <code>cm-codeintell</code></li><li><strong>When:</strong> When the task is complex and requires multi-dimensional analysis (tech, product, design, business) before planning.</li><li><strong>Action:</strong><ol><li>Scan codebase with <strong>code intelligence</strong> (AST graph + architecture diagram via <code>cm-codeintell</code>).</li><li>Interview user and analyze with 9 Windows (TRIZ).</li><li>Propose 2-3 options, evaluate multi-dimensionally, recommend the best option.</li></ol></li><li><strong>Output:</strong> <code>brainstorm-output.md</code> — qualified problem + recommended option → passes to <code>cm-planning</code>.</li></ul><hr><h3 id="phase-1-planning-design-📐" tabindex="-1">Phase 1: Planning &amp; Design 📐 <a class="header-anchor" href="#phase-1-planning-design-📐" aria-label="Permalink to &quot;Phase 1: Planning &amp; Design 📐&quot;">​</a></h3><blockquote><p><strong>Understand the &#39;Job to be Done&#39; (JTBD) and architecture before writing code.</strong></p></blockquote><ul><li><strong>Skill:</strong> <code>cm-planning</code> (Combines brainstorming + writing-plans)</li><li><strong>Action:</strong><ol><li>Brainstorm requirements and analyze i18n.</li><li>Propose architecture and tech stack.</li><li>Write detailed <code>implementation_plan.md</code>.</li></ol></li><li><strong>Output:</strong> Design documentation and execution plan approved by user.</li></ul><hr><h3 id="phase-2-implementation-tdd-execution-💻" tabindex="-1">Phase 2: Implementation (TDD &amp; Execution) 💻 <a class="header-anchor" href="#phase-2-implementation-tdd-execution-💻" aria-label="Permalink to &quot;Phase 2: Implementation (TDD &amp; Execution) 💻&quot;">​</a></h3><blockquote><p><strong>Turn the plan into actual source code safely.</strong></p></blockquote><ul><li><strong>Skills:</strong><ul><li><code>cm-tdd</code>: Red-Green-Refactor cycle. No production code without a failing test first.</li><li><code>cm-execution</code>: Execute plans intelligently (Manual, Parallel, or Subagent mode).</li><li><code>cm-project-bootstrap</code>: For new projects — setup repo, i18n, SEO, and deploy pipeline from Day 0.</li><li><code>cm-git-worktrees</code>: Isolate different work items to avoid state mixing.</li></ul></li></ul><hr><h3 id="phase-3-quality-control-verification-✅" tabindex="-1">Phase 3: Quality Control &amp; Verification ✅ <a class="header-anchor" href="#phase-3-quality-control-verification-✅" aria-label="Permalink to &quot;Phase 3: Quality Control &amp; Verification ✅&quot;">​</a></h3><blockquote><p><strong>Prove with evidence, not words.</strong></p></blockquote><ul><li><strong>Skills:</strong><ul><li><code>cm-quality-gate</code>: Setup test infrastructure (<code>test:gate</code>) and verify output before claiming &quot;done&quot;.</li><li><code>cm-debugging</code>: When tests fail, use systematic investigation framework to find root cause.</li><li><code>cm-code-review</code>: Professional request and feedback review process.</li></ul></li></ul><hr><h3 id="phase-4-safe-deployment-🚀" tabindex="-1">Phase 4: Safe Deployment 🚀 <a class="header-anchor" href="#phase-4-safe-deployment-🚀" aria-label="Permalink to &quot;Phase 4: Safe Deployment 🚀&quot;">​</a></h3><blockquote><p><strong>Ship code without fear of incidents.</strong></p></blockquote><ul><li><strong>Skills:</strong><ul><li><code>cm-safe-deploy</code>: Run 8-gate pipeline (Secret → Syntax → Test → Build → Deploy → Smoke).</li><li><code>cm-safe-i18n</code>: Translate and synchronize languages consistently across the entire project.</li><li><code>cm-terminal</code>: Monitor all terminal commands to detect errors immediately.</li></ul></li></ul><hr><h2 id="codymaster-kit-—-60-skills-summary" tabindex="-1">CodyMaster Kit — 60 Skills Summary <a class="header-anchor" href="#codymaster-kit-—-60-skills-summary" aria-label="Permalink to &quot;CodyMaster Kit — 60 Skills Summary&quot;">​</a></h2><h3 id="🔧-engineering" tabindex="-1">🔧 Engineering <a class="header-anchor" href="#🔧-engineering" aria-label="Permalink to &quot;🔧 Engineering&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>Primary Function</th></tr></thead><tbody><tr><td><code>cm-tdd</code></td><td>Strict Red-Green-Refactor TDD — no code without failing test first.</td></tr><tr><td><code>cm-debugging</code></td><td>Systematic 5-phase error investigation (root cause first).</td></tr><tr><td><code>cm-quality-gate</code></td><td>6-gate verification: static analysis → blind review → ship.</td></tr><tr><td><code>cm-test-gate</code></td><td>Setup 4-layer test infrastructure (unit → integration → e2e → security).</td></tr><tr><td><code>cm-code-review</code></td><td>Manage PR lifecycle: request → receive feedback → complete branch.</td></tr><tr><td><code>cm-codeintell</code></td><td>AST knowledge graph + architecture diagrams + smart context (30% fewer tokens).</td></tr></tbody></table><h3 id="⚙️-operations" tabindex="-1">⚙️ Operations <a class="header-anchor" href="#⚙️-operations" aria-label="Permalink to &quot;⚙️ Operations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>Primary Function</th></tr></thead><tbody><tr><td><code>cm-safe-deploy</code></td><td>Multi-gate deploy pipeline with rollback strategy.</td></tr><tr><td><code>cm-identity-guard</code></td><td>Verify account before push/deploy to prevent wrong-project incidents.</td></tr><tr><td><code>cm-git-worktrees</code></td><td>Isolate feature work in separate worktrees — no state mixing.</td></tr><tr><td><code>cm-terminal</code></td><td>Safe terminal execution with progress logging and error capture.</td></tr><tr><td><code>cm-secret-shield</code></td><td>Defense-in-depth: pre-commit hooks, repo scanning, token lifecycle.</td></tr><tr><td><code>cm-safe-i18n</code></td><td>Safe multi-language management with multi-pass batching and 8-gate audit.</td></tr></tbody></table><h3 id="🎨-product" tabindex="-1">🎨 Product <a class="header-anchor" href="#🎨-product" aria-label="Permalink to &quot;🎨 Product&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>Primary Function</th></tr></thead><tbody><tr><td><code>cm-project-bootstrap</code></td><td>Full project setup: design system → CI → staging → deploy from Day 0.</td></tr><tr><td><code>cm-brainstorm-idea</code></td><td>Strategic analysis gate: 9 Windows + Double Diamond → 2-3 qualified options.</td></tr><tr><td><code>cm-planning</code></td><td>Brainstorm intent → write implementation plan → coordinate execution.</td></tr><tr><td><code>cm-ux-master</code></td><td>48 UX Laws + 37 Design Tests + Figma/Stitch + BM25 semantic design search.</td></tr><tr><td><code>cm-ui-preview</code></td><td>Live UI concept generation via Google Stitch or Pencil MCP.</td></tr><tr><td><code>cm-dockit</code></td><td>Generate complete knowledge bases, SOPs, and API docs from codebase.</td></tr><tr><td><code>cm-readit</code></td><td>Web audio engine: TTS reader, MP3 audio player, Voice CRO trigger system.</td></tr><tr><td><code>cm-jtbd</code></td><td>JTBD customer discovery: Switch Interview → Canvas → Opportunity Scoring.</td></tr></tbody></table><h3 id="📈-growth" tabindex="-1">📈 Growth <a class="header-anchor" href="#📈-growth" aria-label="Permalink to &quot;📈 Growth&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>Primary Function</th></tr></thead><tbody><tr><td><code>cm-content-factory</code></td><td>Self-learning content engine: research → generate → audit → deploy.</td></tr><tr><td><code>cm-ads-tracker</code></td><td>Conversion tracking setup: GTM, Meta CAPI, TikTok, Google Ads.</td></tr><tr><td><code>cm-cro-methodology</code></td><td>CRO audit: funnel mapping → persuasion assets → A/B test design.</td></tr></tbody></table><h3 id="🎯-orchestration" tabindex="-1">🎯 Orchestration <a class="header-anchor" href="#🎯-orchestration" aria-label="Permalink to &quot;🎯 Orchestration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>Primary Function</th></tr></thead><tbody><tr><td><code>cm-execution</code></td><td>Execute plans: Manual / Parallel / Subagent / RARV batch modes.</td></tr><tr><td><code>cm-continuity</code></td><td>Working memory protocol: read at session start, update at session end.</td></tr><tr><td><code>cm-skill-mastery</code></td><td>Meta-skill: when to invoke which skill, how to create new skills.</td></tr><tr><td><code>cm-skill-chain</code></td><td>Compose skills into automated multi-step pipelines (5 built-in chains).</td></tr><tr><td><code>cm-skill-index</code></td><td>Progressive disclosure index — 90% token savings on skill discovery.</td></tr><tr><td><code>cm-deep-search</code></td><td>Semantic search via qmd for large codebases (&gt;200 src / &gt;50 docs files).</td></tr><tr><td><code>cm-how-it-work</code></td><td>Full vibe coding guide — phases, skills per phase, use cases.</td></tr></tbody></table><h3 id="🖥️-workflow-commands" tabindex="-1">🖥️ Workflow Commands <a class="header-anchor" href="#🖥️-workflow-commands" aria-label="Permalink to &quot;🖥️ Workflow Commands&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Skill</th><th>Primary Function</th></tr></thead><tbody><tr><td><code>cm-start</code></td><td>Orchestrate full workflow from objective to production code.</td></tr><tr><td><code>cm-dashboard</code></td><td>Render Kanban board from cm-tasks.json — visual status overview.</td></tr><tr><td><code>cm-status</code></td><td>Ultra-concise 1-2 sentence progress summary (what&#39;s done, what&#39;s next).</td></tr></tbody></table><h2 id="🚀-autonomous-workflow-system" tabindex="-1">🚀 Autonomous Workflow System <a class="header-anchor" href="#🚀-autonomous-workflow-system" aria-label="Permalink to &quot;🚀 Autonomous Workflow System&quot;">​</a></h2><p>The kit supports autonomous mode by applying the <strong>Reason → Act → Reflect → Verify (RARV)</strong> loop.</p><h3 id="how-to-use-the-workflow" tabindex="-1">How to Use the Workflow: <a class="header-anchor" href="#how-to-use-the-workflow" aria-label="Permalink to &quot;How to Use the Workflow:&quot;">​</a></h3><ol><li><strong><code>/cm-start [objective]</code></strong>: Start work. The system will automatically create <code>cm-tasks.json</code>, break down tasks, launch the tracking interface, and autonomously use CM skills to complete them.</li><li><strong><code>/cm-dashboard</code></strong>: Open the visual tracking Dashboard in browser (shows Kanban board, reasoning log, and progress).</li><li><strong><code>/cm-status</code></strong>: View quick progress summary in Terminal.</li></ol><hr><h2 id="💡-activation-guide-by-use-cases" tabindex="-1">💡 Activation Guide by Use Cases <a class="header-anchor" href="#💡-activation-guide-by-use-cases" aria-label="Permalink to &quot;💡 Activation Guide by Use Cases&quot;">​</a></h2><p>There are 2 ways to use CodyMaster: <strong>Fully autonomous (Via Workflows)</strong> or <strong>Manual skill activation (Via Prompting)</strong>.</p><h3 id="_1-build-new-feature-new-project-autonomous" tabindex="-1">1. Build New Feature / New Project (Autonomous) <a class="header-anchor" href="#_1-build-new-feature-new-project-autonomous" aria-label="Permalink to &quot;1. Build New Feature / New Project (Autonomous)&quot;">​</a></h3><blockquote><p>Best way to delegate complete work packages.</p></blockquote><ul><li><strong>Command:</strong> <code>/cm-start &quot;Build user management feature with list screen and CRUD form&quot;</code></li><li><strong>Implicit flow:</strong> Planning → create Task JSON → sub-agents continuously run <code>cm-tdd</code> and <code>cm-quality-gate</code> for each task until done.</li></ul><h3 id="_2-fix-production-bug-manual" tabindex="-1">2. Fix Production Bug (Manual) <a class="header-anchor" href="#_2-fix-production-bug-manual" aria-label="Permalink to &quot;2. Fix Production Bug (Manual)&quot;">​</a></h3><blockquote><p>Bugs need close supervision and AI should not blindly change too much code.</p></blockquote><ul><li><strong>Step 1:</strong> Activate <code>cm-debugging</code> to find Root Cause.</li><li><strong>Step 2:</strong> Activate <code>cm-tdd</code> to write test reproducing the bug and fix it.</li><li><strong>Step 3:</strong> Activate <code>cm-safe-deploy</code> to ship code safely.</li></ul><h3 id="_3-setup-new-project-from-scratch" tabindex="-1">3. Setup New Project From Scratch <a class="header-anchor" href="#_3-setup-new-project-from-scratch" aria-label="Permalink to &quot;3. Setup New Project From Scratch&quot;">​</a></h3><blockquote><p>Establish a solid foundation to avoid technical debt later.</p></blockquote><ul><li><strong>Command:</strong> &quot;Use <code>cm-identity-guard</code> to ensure correct account, then run <code>cm-project-bootstrap</code> to setup a new Next.js project.&quot;</li></ul><h3 id="_4-batch-multi-language-translation" tabindex="-1">4. Batch Multi-Language Translation <a class="header-anchor" href="#_4-batch-multi-language-translation" aria-label="Permalink to &quot;4. Batch Multi-Language Translation&quot;">​</a></h3><blockquote><p>Tedious work that&#39;s error-prone if AI loses focus.</p></blockquote><ul><li><strong>Command:</strong> &quot;Use <code>cm-safe-i18n</code> to extract all hardcoded text in <code>/components</code> directory to <code>vi.json</code> and <code>en.json</code> files.&quot;</li></ul><hr><h2 id="_9-golden-rules" tabindex="-1">9 Golden Rules <a class="header-anchor" href="#_9-golden-rules" aria-label="Permalink to &quot;9 Golden Rules&quot;">​</a></h2><ol><li><strong>Identity First:</strong> Verify account (<code>cm-identity-guard</code>) before push/deploy.</li><li><strong>Design Before Code:</strong> Always have an approved plan before typing.</li><li><strong>i18n Day 0:</strong> Always consider multi-language from the brainstorm step.</li><li><strong>Test Before Code:</strong> RED → GREEN → REFACTOR. No exceptions (<code>cm-tdd</code>).</li><li><strong>Evidence Over Claims:</strong> Only trust terminal/test results output, not AI &quot;saying&quot; it&#39;s done.</li><li><strong>Deploy via Gates:</strong> 8 gates must pass sequentially. Any gate fails = STOP (<code>cm-safe-deploy</code>).</li><li><strong>Safe Secrets:</strong> Never commit secrets. Pre-commit hooks protect every push (<code>cm-secret-shield</code>).</li><li><strong>Parallel Power:</strong> Use parallel execution for i18n or multi-bug fixes (<code>cm-execution</code>).</li><li><strong>Working Memory:</strong> Read CONTINUITY.md at session start, update at session end (<code>cm-continuity</code>).</li></ol>',65)])])}const g=t(r,[["render",n]]);export{m as __pageData,g as default};
